{
  "mode": "io",
  "tests": [
    {
      "name": "basic_resizing",
      "input": "input_image_1080x1920.jpg",
      "output": "output_image_1200x628.jpg",
      "notes": "Tests basic resizing from a common resolution to a Facebook Ads size."
    },
    {
      "name": "focal_point_preservation",
      "input": "input_image_800x600.jpg with focal point at (400, 300)",
      "output": "output_image_400x300.jpg",
      "notes": "Ensures focal point is preserved during resizing."
    },
    {
      "name": "background_extension",
      "input": "input_image_500x500.jpg with background",
      "output": "output_image_800x800.jpg",
      "notes": "Tests background extension capability when increasing dimensions."
    },
    {
      "name": "aspect_ratio_change",
      "input": "input_image_1920x1080.jpg",
      "output": "output_image_1080x1920.jpg",
      "notes": "Tests changing aspect ratio from landscape to portrait."
    },
    {
      "name": "edge_case_small_image",
      "input": "input_image_50x50.jpg",
      "output": "output_image_300x300.jpg",
      "notes": "Tests resizing a very small image to a larger size."
    },
    {
      "name": "edge_case_large_image",
      "input": "input_image_10000x10000.jpg",
      "output": "output_image_1920x1080.jpg",
      "notes": "Tests handling of extremely large images for resizing."
    },
    {
      "name": "multiple_outputs",
      "input": "input_image_1200x800.jpg",
      "output": "[output_image_1080x1920.jpg, output_image_1200x628.jpg]",
      "notes": "Tests generating multiple outputs from a single input."
    },
    {
      "name": "no_key_subject_loss",
      "input": "input_image_800x600.jpg with key subject at (200, 150)",
      "output": "output_image_300x250.jpg",
      "notes": "Ensures no key subject is lost during cropping and resizing."
    }
  ],
  "assumptions": "The input images are valid and accessible.",
  "notes": "Focus on maintaining visual fidelity and preserving key subjects."
}
